#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

float corr = uTexSize.xy*texsize_noise_lq.zw;
vec2 uv1 = vec2(vUv.x-0.5,vUv.y-0.5)*uAspect.xy;
vec3 ret1 = GetBlur1(vUv) ;

vec2 zz = vUv.xy * uTexSize.xy *.03;
float h1 = (cos(zz.y*1) * sin(-zz.y));
float h2 = (sin(zz.x) * cos(zz.y*-1));

vUv.xy -= vec2(h1,h2)*uTexSize.zw * 12;

ret = texture(sampler_main,vUv)*0.98-0.008;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv = (vUv-0.5)*2 / (1+vRadius)+0.5;
uv1 = (vUv-0.5)*uAspect.xy*(1.2+rand_preset.y*0.4) + 0.5 ;
//uv1 = 1- abs(fract((uv1-0.5) * 0.5 )*2 - 1.0);

ang1 = (q1/7+q2/9+q3/11)-q26;
ang1 *= 1.8;
ca = cos(ang1);
sa = sin(ang1);

for (int n = 1; n <= 5; n++)
{  uv1 = multiply(uv1-0.5,mat2(ca,sa,-sa,ca))+0.5;
   uv1 = vec2((uv1.x), (abs(uv1.y-size)+size)); }

uv1 = (uv1-fc)*uAspect.yx+fc + 0.1*cos(q4*2.72);
uv1 = fract(uv1);
dz.x = lum(2*GetBlur1 (uv1-hor) - 2*GetBlur1 (uv1+hor));
dz.y = lum(2*GetBlur1 (uv1-ver) - 2*GetBlur1 (uv1+ver));

uv4 = uv1*.15+2*vUv;
float noise = (texture(sampler_noise_lq,uv4*1.4).r+0.25);
noise *= 1-texture(sampler_noise_lq,uv4*1.4+uTexSize.zw*-4).r;
noise *= (1 + (lum (texture(sampler_rand00,uv4) >0.5)));

uv3 = uv1;
float k1 = clamp01(q21-vRadius);
ret = (.08+1.2*(1.2-k1)*GetBlur2(uv3))*noise;
//ret = max(ret,0.5*k1/length(cos(12*uv3)+dz*16) * normalize(GetBlur1(uv3)));
vec3 lig = k1/(length(cos(12*uv3)+dz*16)+0.07) * (GetBlur1(uv3)+0.);
ret = max(ret,lig) + 0.*k1*lig;

ang1 = q28/2;
ca = cos(ang1);
sa = sin(ang1);
for (int n = 1; n <= 2; n++)
{  uv1 = multiply(uv1-0.5,mat2(ca,sa,-sa,ca))+0.5;
  uv1 = vec2((uv1.y), (abs(uv1.x-size)+size));}

ret += (1-vRadius)*0.6*clamp01(.05/abs(length(cos(8*uv1.x)))-0.5)*noise;
k1 = clamp01(2.2-3*length(vUv-0.5));
ret = mix(lum(ret), ret, k1);
ret *= k1*1.6;


  fragColor = ret;
}
